class Solution {
public:
    int flipLights(int n, int presses) {
        n = min(n, 63); // Since 2^6 > 63, we only need to consider 6 bits
        if (presses == 0) return 1;
        return (1 << (min(n, presses) + 1)) - (presses & 1 ? 0 : 1);
    }
};
